    uz = u * v.z;
    c1 = ux * v.y;
    c2 = ux * v.z;
    c3 = uz * v.y;
    return new Mat44([
        e + ux * v.x,
        c1 + v.z,
        c2 - v.y,
        0.0,
        c1 - v.z,
