    scale: Vec3;

    constructor(that?: Transform | Mat33 | Mat44 | TransformParams) {
        // Default initialization
        this.rotation = new Quaternion();
        this.translation = new Vec3();
        this.scale = new Vec3(1, 1, 1);

        if (that) {
            if (that instanceof Transform) {
                this.rotation = new Quaternion(that.rotation);
                this.translation = new Vec3(that.translation);
                this.scale = new Vec3(that.scale);
            } else if (that instanceof Mat33 || that instanceof Mat44) {
                const decomposed = that.decompose();
                this.rotation = decomposed["rotation"];
                this.translation = decomposed["translation"] || new Vec3();
                this.scale = decomposed["scale"];
            } else {
                // TransformParams
                const obj = that as TransformParams;
                if (obj.rotation) this.rotation = new Quaternion(obj.rotation);
                if (obj.translation) this.translation = new Vec3(obj.translation);
                if (obj.scale !== undefined) {
                    if (typeof obj.scale === 'number') {
                        this.scale = new Vec3(obj.scale, obj.scale, obj.scale);
                    } else {
                        this.scale = new Vec3(obj.scale);
                    }
                }
            }
        }
    }

    rotateXTo(x: Vec3 | number[]): Transform {
        const rot = Quaternion.rotationFromTo(this.xAxis(), x);
        this.rotation = rot.multQuat(this.rotation);
        return this;
    }

    rotateYTo(y: Vec3 | number[]): Transform {
        const rot = Quaternion.rotationFromTo(this.yAxis(), y);
        this.rotation = rot.multQuat(this.rotation);
        return this;
    }

    rotateZTo(z: Vec3 | number[]): Transform {
        const rot = Quaternion.rotationFromTo(this.zAxis(), z);
        this.rotation = rot.multQuat(this.rotation);
        return this;
    }

    xAxis(): Vec3 {
        return this.rotation.xAxis();
    }

    yAxis(): Vec3 {
        return this.rotation.yAxis();
    }

    zAxis(): Vec3 {
        return this.rotation.zAxis();
    }

    axes(): { x: Vec3; y: Vec3; z: Vec3 } {
        return this.rotation.axes();
    }

    scaleMatrix(): Mat44 {
        return Mat44.scale(this.scale);
    }

    rotationMatrix(): Mat44 {
        return this.rotation.matrix().toMat44();
    }

    translationMatrix(): Mat44 {
        return Mat44.translation(this.translation);
    }

    matrix(): Mat44 {
        // T * R * S
        return this.translationMatrix()
            .multMat44(this.rotationMatrix())
            .multMat44(this.scaleMatrix());
    }

    inverseScaleMatrix(): Mat44 {
        return Mat44.scale([
            1 / this.scale.x,
            1 / this.scale.y,
            1 / this.scale.z
