        let w: number;
        let x: number;
        let y: number;
        let z: number;
        if (that instanceof Array) {
            w = that[0];
            x = that[1];
            y = that[2];
            z = that[3];
        } else {
            w = that.w;
            x = that.x;
            y = that.y;
            z = that.z;
