        epsilon = epsilon === undefined ? 0 : epsilon;
        return (this.w === w || Math.abs(this.w - w) <= epsilon) &&
            (this.x === x || Math.abs(this.x - x) <= epsilon) &&
            (this.y === y || Math.abs(this.y - y) <= epsilon) &&
            (this.z === z || Math.abs(this.z - z) <= epsilon);
    }

    normalize(): Quaternion {
        const mag = Math.sqrt(
            this.x * this.x +
                this.y * this.y +
