        const f = Math.abs(e);

        let x: Vec3;
        let u: Vec3;
        let v: Vec3;

        if (f > (1.0 - EPSILON)) {
            const fx = Math.abs(from.x);
            const fy = Math.abs(from.y);
            const fz = Math.abs(from.z);
            if (fx < fy) {
                if (fx < fz) {
                    x = new Vec3(1, 0, 0);
                } else {
                    x = new Vec3(0, 0, 1);
                }
